from vpython import * #Web VPython 3.2 from vpython import * #Web VPython 3.2 # ========================================== # 3D Dynamics: Sharp Egg-Shaped Orbit # ========================================== # 1. VISUAL SETUP scene = canvas(title="Sharp Egg-Shaped Orbital Lab", width=900, height=550, background=color.gray(0.05)) scene.lights = [] scene.ambient = color.gray(0.15) sunlight = distant_light(direction=vec(1, 0.2, 0.5), color=color.white) # --- GRAPH SETUP (Continuous Scrolling vs Time) --- energy_graph = graph(width=900, height=300, title="Energy vs Time", xtitle="Time (s)", ytitle="Energy (J)", background=color.black, fast=True) k_curve = gcurve(color=color.red, label="Kinetic Energy") p_curve = gcurve(color=color.blue, label="Potential Energy") # 2. PHYSICS CONSTANTS G = 6.674e-11 M_earth = 5.972e24 R_earth = 6.371e6 m_sat = 1500.0 # 3. CREATE THE SHARP EARTH earth = sphere(pos=vec(0,0,0), radius=R_earth * 1.5, color=vec(0.1, 0.3, 0.8), shininess=1, emissive=False) # 4. CREATE THE SATELLITE (🛰️) body = box(pos=vec(0,0,0), size=vec(1.5e6, 1.5e6, 1.5e6), color=color.gray(0.8)) panel1 = box(pos=vec(2.0e6, 0, 0), size=vec(2.8e6, 1.0e6, 0.1e6), color=vec(0.2, 0.4, 1.0)) panel2 = box(pos=vec(-2.0e6, 0, 0), size=vec(2.8e6, 1.0e6, 0.1e6), color=vec(0.2, 0.4, 1.0)) sat_shape = compound([body, panel1, panel2], make_trail=True, trail_color=color.yellow, trail_type="curve", trail_radius=5e4, retain=1000) # 5. INITIAL KINEMATICS (Egg Shape Setup) alt = 5.0e7 sat_shape.pos = vec(R_earth + alt, 0, 0) sat_shape.v = vec(0, 2200, 400) # 6. CALCULATE FIXED ORBITAL PERIOD r0 = mag(sat_shape.pos) v0 = mag(sat_shape.v) energy_per_mass = (0.5 * v0**2) - (G * M_earth / r0) a_axis = -G * M_earth / (2 * energy_per_mass) T_period = 2 * pi * sqrt(abs(a_axis)**3 / (G * M_earth)) scene.caption = "\n<b>ORBITAL CONSTANTS (Fixed)</b>\n" scene.caption += "Satellite Mass: " + str(m_sat) + " kg\n" scene.caption += "Calculated Orbit Time: " + str(round(T_period/3600, 2)) + " hours\n" scene.caption += "------------------------------------------\n" telemetry = label(pixel_pos=True, pos=vec(20, 80, 0), text='', height=16, color=color.white, box=False, align='left') # 7. SIMULATION LOOP t = 0 dt = 250 sum_speed = 0 sum_accel = 0 count = 0 while True: rate(150) # Physics calculations r_vec = sat_shape.pos - earth.pos r_mag = mag(r_vec) a_scalar = (G * M_earth) / (r_mag**2) a_vec = -a_scalar * norm(r_vec) # Euler-Cromer Integration sat_shape.v += a_vec * dt sat_shape.pos += sat_shape.v * dt # --- UPDATED CONTINUOUS PLOTTING (Energy vs Time) --- v_mag = mag(sat_shape.v) ke_val = 0.5 * m_sat * (v_mag**2) pe_val = -G * M_earth * m_sat / r_mag # Plotting against time 't' allows the graph to scroll indefinitely k_curve.plot(t, ke_val) p_curve.plot(t, pe_val) # Update Statistics count += 1 sum_speed += v_mag sum_accel += a_scalar # Update Live Label msg = "Current Speed: {0} km/s\nAvg Speed: {1} km/s\nAvg Accel: {2} m/s²" telemetry.text = msg.format(round(v_mag/1000, 2), round((sum_speed/count)/1000, 2), round(sum_accel/count, 4)) # Camera Dynamics angle = t * 0.5e-5 scene.camera.pos = vec(1.1e8 * cos(angle), 4.0e7, 1.1e8 * sin(angle)) scene.camera.axis = -scene.camera.pos t += dt if r_mag < R_earth: telemetry.text = "IMPACT DETECTED" break